// INITIALIZATION — year tabs set up on DOMContentLoaded only (translations init handled by app.js)
document.addEventListener('DOMContentLoaded', () => {
    setupYearTabs();
});

function setupYearTabs() {
    const tabs = document.querySelectorAll('.year-tab');
    tabs.forEach(tab => {
        tab.addEventListener('click', () => {
            tabs.forEach(t => t.classList.remove('active'));
            tab.classList.add('active');
            currentYear = tab.dataset.year;
            renderModules();
        });
    });
}

export function renderModules() {
    const grid = document.getElementById('lessons-grid');
    if (!grid) return;

    grid.innerHTML = '';
    const filteredModules = modulesData.filter(m => m.year === currentYear);

    filteredModules.forEach(module => {
        const lessonCount = lessonsData.filter(l => l.module === module.id).length;
        const card = document.createElement('div');
        card.className = 'module-card';
        card.style.setProperty('--accent-color', module.color);
        card.innerHTML = `
            <div class="module-header" style="background: ${module.color}15">
                <div class="module-icon" style="color: ${module.color}">${module.icon}</div>
                <div class="module-tag" style="border-color: ${module.color}; color: ${module.color}">${t('lessons.count_label') || 'Lessons'}: ${lessonCount}</div>
            </div>
            <div class="module-body">
                <h3>${module.title[currentLang] || module.title['en']}</h3>
                <p>${module.desc[currentLang] || module.desc['en']}</p>
            </div>
            <div class="module-footer">
                <button class="module-open-btn" style="background: ${module.color}">${t('lessons.btn_open') || 'Open Module'}</button>
            </div>
        `;
        card.querySelector('button').addEventListener('click', () => openModule(module));
        grid.appendChild(card);
    });
}

function openModule(module) {
    playSound('click');
    const grid = document.getElementById('lessons-grid');
    const detail = document.getElementById('lesson-detail');
    const ticker = document.getElementById('geo-feed-ticker');
    const yearSel = document.getElementById('year-selector');

    if (ticker) ticker.style.display = 'none';
    if (yearSel) yearSel.style.display = 'none';

    renderModuleLessons(module);
}

export function renderModuleLessons(module) {
    const grid = document.getElementById('lessons-grid');
    const detail = document.getElementById('lesson-detail');
    const titleDisplay = document.getElementById('module-title-display');
    const listContainer = document.getElementById('module-lessons-list');

    titleDisplay.textContent = module.title[currentLang] || module.title['en'];
    listContainer.innerHTML = '';

    const lessons = lessonsData.filter(l => l.module === module.id);
    
    if (lessons.length === 0) {
        listContainer.innerHTML = `<p class="no-lessons-msg">${t('lessons.no_content') || 'No lessons yet.'}</p>`;
    }

    lessons.forEach(lesson => {
        const item = document.createElement('div');
        item.className = 'lesson-list-item';
        item.innerHTML = `
            <div class="lesson-info">
                <h4>${lesson.title[currentLang] || lesson.title['en']}</h4>
                <div class="lesson-meta">
                    <span class="xp-badge">⚡ ${lesson.xpReward} XP</span>
                </div>
            </div>
            <button class="lesson-start-btn">${t('lessons.btn_start') || 'Start'}</button>
        `;
        item.querySelector('button').addEventListener('click', () => showLessonContent(lesson));
        listContainer.appendChild(item);
    });

    grid.classList.add('hidden');
    detail.classList.remove('hidden');
}

export function showLessonContent(lesson) {
    const modal = document.getElementById('lesson-modal') || document.getElementById('lesson-modal-overlay');
    if (!modal) return;
    
    const title = document.getElementById('lesson-modal-title');
    const body = document.getElementById('lesson-modal-body');
    const completeBtn = document.getElementById('lesson-complete-btn');

    title.textContent = lesson.title[currentLang] || lesson.title['en'];
    let contentHTML = '';
    if (lesson.image) contentHTML += `<div class="lesson-image-container"><img src="${lesson.image}"></div>`;
    contentHTML += `<div class="lesson-rich-content">${lesson.content[currentLang] || lesson.content['en']}</div>`;
    body.innerHTML = contentHTML;

    // Attach game launchers
    const launchers = body.querySelectorAll('.lesson-game-launcher');
    launchers.forEach(btn => {
        btn.addEventListener('click', (e) => {
            const gameId = e.target.getAttribute('data-game');
            modal.classList.add('hidden');
            // Trigger custom event to switch to games tab
            document.dispatchEvent(new CustomEvent('launch-game', { detail: { game: gameId } }));
            
            // Also explicitly switch the UI view just in case
            document.querySelectorAll('.nav-link').forEach(l => l.classList.remove('active'));
            const gameTab = document.querySelector('[data-page="games"]');
            if (gameTab) gameTab.classList.add('active');
            document.querySelectorAll('.page').forEach(p => p.classList.remove('active'));
            const gamesPage = document.getElementById('page-games');
            if (gamesPage) gamesPage.classList.add('active');
        });
    });

    modal.classList.remove('hidden');
}

export function initLessons() {
    renderModules();
    const backBtn = document.getElementById('lesson-back-btn');
    if (backBtn) {
        backBtn.addEventListener('click', () => {
            document.getElementById('lessons-grid').classList.remove('hidden');
            document.getElementById('lesson-detail').classList.add('hidden');
            const ticker = document.getElementById('geo-feed-ticker');
            const yearSel = document.getElementById('year-selector');
            if (ticker) ticker.style.display = 'flex';
            if (yearSel) yearSel.style.display = 'flex';
        });
    }

    // Modal close logic
    const modal = document.getElementById('lesson-modal') || document.getElementById('lesson-modal-overlay');
    const closeBtn = document.getElementById('lesson-modal-close');
    const completeBtn = document.getElementById('lesson-complete-btn');
    
    if (closeBtn && modal) {
        closeBtn.addEventListener('click', () => {
            modal.classList.add('hidden');
        });
    }

    if (completeBtn && modal) {
        completeBtn.addEventListener('click', () => {
            modal.classList.add('hidden');
            // Assuming the lesson object is passed and XP is awarded
            // The XP logic is probably handled by app.js when custom events are fired
            document.dispatchEvent(new CustomEvent('xpGained', { detail: { amount: 50, reason: 'Lesson Completed!' } }));
            showToast('Lesson Completed! +50 XP', 'success');
        });
    }
}
